const fs = require('fs');
const path = require('path');
const { allProducts } = require('../core/products.js');
const { AppError } = require('../lib/errors.js');
const config = require('../config.js');

const SUPPORTED_FORMATS = ['csv', 'json'];

function exportProducts(args) {
  let format = 'csv';
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--format' && i + 1 < args.length) {
      format = args[++i];
    }
  }
  if (!SUPPORTED_FORMATS.includes(format)) {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  const products = allProducts();
  const outDir = config.outputDir;
  const outPath = path.join(outDir, `products.${format}`);

  fs.mkdirSync(outDir, { recursive: true });

  if (format === 'csv') {
    const lines = ['id,name,price'];
    for (const p of products) {
      lines.push(`${p.id},${p.name},${p.price}`);
    }
    fs.writeFileSync(outPath, lines.join('\n') + '\n');
  } else {
    fs.writeFileSync(outPath, JSON.stringify(products, null, 2) + '\n');
  }

  return [`Exported ${products.length} products to ${outPath}`];
}

module.exports = { exportProducts };

